// Parse Gemini response and extract the JSON
const rawResponse = $input.first().json;
let parsed;

try {
  // Gemini returns content in candidates[0].content.parts[0].text
  const text = rawResponse.candidates[0].content.parts[0].text;
  parsed = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch(e) {
  // Fallback: try parsing rawResponse directly
  parsed = rawResponse;
}

// Add metadata
parsed.topic_input = $('Get Next Topic').first().json.TOPIC;
parsed.pillar = $('Get Next Topic').first().json.PILLAR;
parsed.generation_timestamp = new Date().toISOString();

// Calculate publish time (schedule 3 days from now at 3PM)
const publishDate = new Date();
publishDate.setDate(publishDate.getDate() + 3);
publishDate.setHours(15, 0, 0, 0);
parsed.scheduled_publish_time = publishDate.toISOString();

// Create temp file paths
parsed.voiceover_path = `/tmp/voiceover_${Date.now()}.mp3`;
parsed.final_video_path = `/tmp/final_${Date.now()}.mp4`;
parsed.clips_dir = `/tmp/clips_${Date.now()}`;

return [{ json: parsed }];

// Extract best image URL from Wikimedia response
const wikiData = $input.first().json;
const pages = wikiData.query?.pages || {};
const pageList = Object.values(pages);

let bestImageUrl = null;
for (const page of pageList) {
  if (page.imageinfo?.[0]?.thumburl) {
    bestImageUrl = page.imageinfo[0].thumburl;
    break;
  }
}

const previousData = $('Parse Gemini Response').first().json;
return [{ json: { ...previousData, real_photo_url: bestImageUrl } }];

// Split veo_prompts array into individual items for batch processing
const data = $('Parse Gemini Response').first().json;
const prompts = data.veo_prompts || [];

return prompts.map((prompt, index) => ({
  json: {
    ...data,
    current_prompt: prompt,
    scene_index: index + 1,
    output_clip_path: `${data.clips_dir}/clip_${String(index + 1).padStart(2, '0')}.mp4`
  }
}));

// Decode base64 audio from Google TTS response
const ttsResponse = $input.first().json;
const audioBase64 = ttsResponse.audioContent;
const audioBuffer = Buffer.from(audioBase64, 'base64');

return [{
  json: $('Parse Gemini Response').first().json,
  binary: {
    voiceover: {
      data: audioBase64,
      mimeType: 'audio/mpeg',
      fileName: 'voiceover.mp3'
    }
  }
}];
